const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const out = {
  client_id: body.client_id || null,
  vacated_appointment_id: body.vacated_appointment_id || null,
  vacated_reason: body.vacated_reason || 'manual',
  slot_start: body.slot_start || null,
  slot_end: body.slot_end || null,
  token: body.token || null
};
if (!out.client_id || !out.slot_start || !out.slot_end) {
  return { json: { _error: true, error: 'client_id, slot_start, slot_end required', ok: false } };
}
if (!out.token) {
  return { json: { _error: true, error: 'token required', ok: false } };
}
return { json: out };

// Normalize candidates into suggestion shape, carry forward request context.
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const parsed = $('Validate + Parse').first().json;
const suggestions = rows.map(function(r, i) {
  return {
    lead_id: r.lead_id,
    score: r.score,
    reason: r.reason,
    rank: i + 1,
    lead_name: r.lead_name || null,
    lead_email: r.lead_email || null,
    lead_phone: r.lead_phone || null
  };
});
return { json: Object.assign({}, parsed, { suggestions }) };

// Build final response shape.
const parsed = $('Validate + Parse').first().json;
const suggestions = parsed.suggestions || [];
const reshuffleResp = $input.item.json;
let reshuffle_id = null;
if (typeof reshuffleResp === 'string') reshuffle_id = reshuffleResp;
else if (reshuffleResp && reshuffleResp.id) reshuffle_id = reshuffleResp.id;
else if (Array.isArray(reshuffleResp) && reshuffleResp.length > 0 && reshuffleResp[0].record_reshuffle) reshuffle_id = reshuffleResp[0].record_reshuffle;
return { json: { ok: true, reshuffle_id, candidates: suggestions } };
